            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 8592247984496276422U) + aNonceWordG;
            aOrbiterH = (aOrbiterH ^ aOrbiterJ) ^ 3395351919795865709U;
            aOrbiterH = RotL64((aOrbiterH * 15444451225902127371U), 53U);
