            //
            aOrbiterF = (aOrbiterF + aOrbiterI) + 13911840761868592338U;
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 3892678319714974040U;
            aOrbiterE = RotL64((aOrbiterE * 364409708667268023U), 3U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterA) + 9553740076043036535U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterK) ^ 8006525716226916253U) ^ aOrbiterUpdateSaltA[(((31U - aIndex) + 12U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 187538397754975883U), 35U);
